      "path": "src/modules/tasks/routes.js",
      "content": "const router = require('express').Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { name, description } = req.body;
  if (!name) return sendError(res, 400, 'BAD_REQUEST', 'Task name is required');
  const task = await tasksService.createTask(req.projectId, name, description);
  if (!task) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  return res.status(201).json({ task });
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  let tasks = await tasksService.getAllTasks(req.projectId);
  if (status) {
    tasks = tasks.filter(t => t.status === status);
  }
  return res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const task = await tasksService.updateTaskStatus(req.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  return res.json({ task });
});

module.exports = router;
