      "content": "const { randomUUID } = require('node:crypto');

let tasks = [];

function getAllTasks(projectId) {
  return tasks.filter(t => t.projectId === projectId);
}

function createTask(projectId, name, description) {
  const task = { id: randomUUID(), projectId, name, description, status: 'todo' };
  tasks.push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasks.findIndex(t => t.projectId === projectId && t.id === taskId);
  if (taskIndex === -1) return null;
  tasks[taskIndex].status = status;
  return tasks[taskIndex];
}

module.exports = {
  getAllTasks,
  createTask,
  updateTaskStatus,
};
